   407→// scopeInjector inject request params into the templated scopes. e.g. "settings:" + eval.Parameters(":id")
   408→func scopeInjector(params scopeParams) ScopeAttributeMutator {
   409→	return func(_ context.Context, scope string) ([]string, error) {
   410→		tmpl, err := template.New("scope").Parse(scope)
   411→		if err != nil {
   412→			return nil, err
   413→		}
   414→		var buf bytes.Buffer
   415→		if err = tmpl.Execute(&buf, params); err != nil {
   416→			return nil, err
   417→		}
   418→		return []string{buf.String()}, nil
   419→	}
   420→}
