   124→	}
   125→
   126→	if signedInUser.Permissions == nil {
   127→		signedInUser.Permissions = make(map[int64]map[string][]string)
   128→	}
   129→
   130→	if signedInUser.Permissions[signedInUser.OrgID] == nil {
